command = sys.argv[1]

if command == "add":
    if len(sys.argv) < 3:
        print("Usage: python todo.py add \"任务内容\"")
        return
    content = sys.argv[2]
    todos = load_todos()
    todos.append(content)
    save_todos(todos)

elif command == "list":
    todos = load_todos()
    for i, todo in enumerate(todos, start=1):
        print(f"{i}: {todo}")

elif command == "remove":
    if len(sys.argv) < 3:
        print("Usage: python todo.py remove <ID>")
        return
    try:
        idx = int(sys.argv[2]) - 1
    except ValueError:
        return
    todos = load_todos()
    if 0 <= idx < len(todos):
        todos.pop(idx)
        save_todos(todos)

else:
    print(f"Unknown command: {command}")

